// ---------- helpers ----------

const dayKey = (d) => {
  const dt = d ? new Date(d) : new Date();
  return dt.getFullYear() + "-" + String(dt.getMonth() + 1).padStart(2, "0") + "-" + String(dt.getDate()).padStart(2, "0");
};

const prettyStamp = (ts) => {
  const d = new Date(ts);
  const mo = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"][d.getMonth()];
  const hh = String(d.getHours()).padStart(2, "0");
  const mm = String(d.getMinutes()).padStart(2, "0");
  return String(d.getDate()).padStart(2, "0") + " " + mo + ", " + hh + ":" + mm;
};

const speciesKey = (common) => (common || "").toLowerCase().trim();
const normName = (s) => (s || "").toLowerCase().replace(/[^a-z\s]/g, " ").replace(/\s+/g, " ").trim();
const tokensOf = (s) => normName(s).split(" ").filter(Boolean);
const sciKey = (s) => {
  const t = tokensOf(s);
  return t.length >= 2 ? t.slice(0, 2).join(" ") : "";
};
const GENERIC_NAMES = new Set(["liana", "vine", "tree", "plant", "bird", "bug", "insect", "mushroom", "fungus", "moss", "grass", "flower", "weed", "shrub", "animal", "leaf", "fern", "rock", "creature"]);

function sameSpecies(aCommon, aSci, bCommon, bSci) {
  const an = normName(aCommon);
  const bn = normName(bCommon);
  if (an && an === bn) return true;
  const as = sciKey(aSci || "");
  const bs = sciKey(bSci || "");
  if (as && as === bs) return true;
  const at = tokensOf(aCommon);
  const bt = tokensOf(bCommon);
  const small = at.length <= bt.length ? at : bt;
  const big = at.length <= bt.length ? bt : at;
  if (big.length - small.length === 1 && small.length >= 1 && small.every((t) => big.includes(t)) && small.some((t) => t.length >= 4)) return true;
  return false;
}

function mergeCaptures(caps) {
  const clusters = [];
  for (const c of caps) {
    const cl = clusters.find((k) => sameSpecies(c.common, c.sci, k.common, k.sci));
    if (!cl) {
      clusters.push({ common: c.common, sci: c.sci });
    } else {
      if (tokensOf(c.common).length > tokensOf(cl.common).length) cl.common = c.common;
      if (!cl.sci && c.sci) cl.sci = c.sci;
    }
  }
  return caps.map((c) => {
    const cl = clusters.find((k) => sameSpecies(c.common, c.sci, k.common, k.sci));
    return cl ? { ...c, common: cl.common, sci: c.sci || cl.sci } : c;
  });
}

const levelFor = (pts) => {
  let idx = 0;
  for (let i = 0; i < LEVELS.length; i++) if (pts >= LEVELS[i].at) idx = i;
  const cur = LEVELS[idx];
  const next = LEVELS[idx + 1] || null;
  const span = next ? next.at - cur.at : 1;
  const into = next ? pts - cur.at : 1;
  return { idx, name: cur.name, next, pct: next ? Math.min(100, Math.round((into / span) * 100)) : 100 };
};

function loadImageFromFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error("read failed"));
    reader.onload = () => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = () => reject(new Error("decode failed"));
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
  });
}

function drawScaled(img, maxSide, quality) {
  const scale = Math.min(1, maxSide / Math.max(img.width, img.height));
  const w = Math.max(1, Math.round(img.width * scale));
  const h = Math.max(1, Math.round(img.height * scale));
  const cv = document.createElement("canvas");
  cv.width = w;
  cv.height = h;
  cv.getContext("2d").drawImage(img, 0, 0, w, h);
  return cv.toDataURL("image/jpeg", quality);
}

async function prepareImage(file) {
  const img = await loadImageFromFile(file);
  const fullUrl = drawScaled(img, 768, 0.72);
  const thumbUrl = drawScaled(img, 300, 0.55);
  return { fullUrl, thumbUrl, apiB64: fullUrl.split(",")[1] };
}

function frameFromVideo(video) {
  const vw = video.videoWidth, vh = video.videoHeight;
  if (!vw || !vh) throw new Error("no frame");
  const make = (maxSide, q) => {
    const s = Math.min(1, maxSide / Math.max(vw, vh));
    const cv = document.createElement("canvas");
    cv.width = Math.max(1, Math.round(vw * s));
    cv.height = Math.max(1, Math.round(vh * s));
    cv.getContext("2d").drawImage(video, 0, 0, cv.width, cv.height);
    return cv.toDataURL("image/jpeg", q);
  };
  const fullUrl = make(768, 0.72);
  const thumbUrl = make(300, 0.55);
  return { fullUrl, thumbUrl, apiB64: fullUrl.split(",")[1] };
}

async function identifyNature(apiB64, questText, dexNames, loc) {
  const prompt =
    "You are The Ranger, the warm and honest judge of Mossback, a game where people photograph real wild nature and collect it like creatures.\n" +
    "Look at the attached photo and identify the single most prominent wild subject: a bird, tree, plant, fern, wildflower, mammal, insect, spider, snail, slug, mushroom, moss or lichen. Garden plants and urban wildlife count. Domestic pets and farm animals count too, as companions. People and man-made objects do not.\n" + (dexNames && dexNames.length ? "The player's dex already contains: " + dexNames.join(", ") + ". If the subject is one of these species, you MUST reuse that exact common name.\n" : "") + "" +
    "Respond ONLY with minified JSON, no markdown fences, exactly this shape:\n" +
    '{"found":true,"quest":false,"category":"birds","common":"American Crow","sci":"Corvus brachyrhynchos","rarity":"common","title":"...","flavour":"...","abilities":["...","..."],"quality":3,"confidence":0.9,"note":"..."}\n' +
    "Rules:\n" +
    "- category is one of: birds, trees, plants, mammals, small, fungi, companions. Insects, spiders, snails and slugs go in small. Moss and lichen go in fungi. Ferns and wildflowers go in plants. Domestic pets and farm animals go in companions; their common name may be the breed if clearly identifiable (a house cat is simply Domestic Cat), and their rarity is always common.\n" +
    "- common is the accepted common species name, always the single most standard form so repeat sightings of the same species match exactly; sci is the Latin binomial, or your best genus if unsure. common must name a real species or at least its genus, NEVER a generic category or growth habit such as liana, vine, tree, bird, insect or mushroom; if you cannot identify at least the genus, set found false and say in note what closer detail would help.\n" +
    "- rarity is one of common, uncommon, rare, epic, legendary, " + (loc ? "judged for how hard it is to encounter around " + loc + " unless the photo is clearly elsewhere." : "judged for how hard it is to encounter in the local region.") + " Ladder: common = seen daily in a city (crow, robin, grey squirrel, dandelion, bigleaf maple); uncommon = takes some looking (Steller's jay, sword fern, banana slug); rare = seasonal or lucky (pileated woodpecker, chanterelle-lookalike fungi, trillium); epic = genuinely hard (owl, river otter, calypso orchid); legendary = a once-a-year story (orca, black bear, mountain lion).\n" +
    "- title is a poetic 2 to 5 word nickname grounded in what is actually in the photo.\n" +
    "- flavour is at most 16 words, present tense, British spelling, no emojis, like a Pokedex entry for the real world.\n" +
    "- abilities is exactly two short invented ability names, 1 to 3 words each, playful and true to the species.\n" +
    "- quality is 1 to 5 for composition, clarity and drama. confidence 0 to 1 for the identification; below 0.35 set found false.\n" +
    "- note: if found, one warm ranger's remark of at most 12 words; if not found, say what you saw instead and encourage, at most 20 words.\n" +
    "- NEVER state or imply that anything is edible, inedible, medicinal or safe to touch, taste or handle. No foraging guidance of any kind. Never describe or identify people; if human faces are prominent, set found false and say scenes, not faces. Animal faces are welcome." +
    (questText ? "\n- Also set quest to true ONLY if this photo clearly satisfies today's quest: '" + questText + "'. Judge fairly but generously." : "");

  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 1000,
      messages: [
        {
          role: "user",
          content: [
            { type: "image", source: { type: "base64", media_type: "image/jpeg", data: apiB64 } },
            { type: "text", text: prompt },
          ],
        },
      ],
    }),
  });
  if (!response.ok) {
    const t = await response.text();
    throw new Error("http " + response.status + ": " + t.slice(0, 160));
  }
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || "api error");
  const text = (data.content || [])
    .filter((b) => b.type === "text")
    .map((b) => b.text)
    .join("");
  const clean = text.replace(/```json|```/g, "").trim();
  const start = clean.indexOf("{");
  const end = clean.lastIndexOf("}");
  let parsed;
  try {
    parsed = JSON.parse(start >= 0 && end > start ? clean.slice(start, end + 1) : clean);
  } catch (e) {
    throw new Error("parse: " + clean.slice(0, 160));
  }
  if (!CATS[parsed.category]) parsed.category = "plants";
  if (!TIERS[parsed.rarity]) parsed.rarity = "common";
  if (parsed.category === "companions") parsed.rarity = "common";
  parsed.quality = Math.min(5, Math.max(1, Math.round(Number(parsed.quality) || 3)));
  if (!Array.isArray(parsed.abilities)) parsed.abilities = [];
  parsed.abilities = parsed.abilities.slice(0, 2).map(String);
  parsed.quest = !!parsed.quest;
  if (parsed.found && GENERIC_NAMES.has(normName(parsed.common))) {
    parsed.found = false;
    parsed.note = "I can see a " + String(parsed.common).toLowerCase() + ", but not which species. Get closer, a leaf, flower or clearer angle helps.";
  }
  return parsed;
}

async function identifyWithRetry(apiB64, questText, dexNames, loc) {
  try {
    return await identifyNature(apiB64, questText, dexNames, loc);
  } catch (e) {
    const m = String((e && e.message) || "");
    if (/^http 4\d\d/.test(m) || /invalid response format/i.test(m)) throw e;
    await new Promise((r) => setTimeout(r, 1200));
    return identifyNature(apiB64, questText, dexNames, loc);
  }
}

async function callApi(body) {
  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!response.ok) {
    const t = await response.text();
    throw new Error("http " + response.status + ": " + t.slice(0, 120));
  }
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || "api error");
  return (data.content || []).filter((b) => b.type === "text").map((b) => b.text).join("");
}

async function fetchLore(common, sci) {
  const prompt =
    "You are The Ranger writing a short field-guide entry for " + common + (sci ? " (" + sci + ")" : "") + ".\n" +
    'Respond ONLY with minified JSON, no markdown fences: {"overview":"...","habitat":"...","range":"...","diet":"...","size":"...","funFact":"...","conservation":"..."}\n' +
    "Accuracy rules: include only well-established, widely documented facts about this exact species. If a detail is uncertain, disputed or highly variable, use broad careful wording or an empty string rather than guessing. Give numbers only when they are standard reference values. British spelling, no emojis, each field at most 30 words, overview at most 45 words. conservation is the IUCN status only if widely known, else an empty string. NEVER state or imply edibility, toxicity for consumption, medicinal use, or that anything is safe to touch, taste, handle or approach.";
  const text = await callApi({ model: "claude-sonnet-4-6", max_tokens: 1000, messages: [{ role: "user", content: prompt }] });
  const clean = text.replace(/```json|```/g, "").trim();
  const s = clean.indexOf("{");
  const e = clean.lastIndexOf("}");
  return JSON.parse(s >= 0 && e > s ? clean.slice(s, e + 1) : clean);
}

