async function fetchDaily(loc) {
  const monthName = ["January","February","March","April","May","June","July","August","September","October","November","December"][new Date().getMonth()];
  const prompt =
    "You are The Ranger of a nature-catching game. Produce today's content.\n" +
    'Respond ONLY minified JSON: {"quest":"...","nearby":[{"name":"Monarch Butterfly","rarity":"common","category":"small"},{"name":"...","rarity":"uncommon","category":"plants"},{"name":"...","rarity":"rare","category":"birds"}],"mystery":{"hint":"..."}}\n' +
    "Rules: quest is ONE playful open-ended daily quest completable anywhere by photographing something wild, at most 12 words, judgeable from a single photo, no specific species or locations, no touching, feeding, collecting or approaching wildlife. " + (loc ? "nearby is exactly 3 real species someone around " + loc + " could plausibly find outdoors in " + monthName + ", one of them rare-tier for aspiration" : "nearby is exactly 3 real, widely distributed species that most players could plausibly encounter somewhere ordinary, one of them rare-tier for aspiration") + "; use accepted common names; rarity one of common, uncommon, rare; category one of birds, trees, plants, mammals, small, fungi. mystery is 1 clue for a real wild thing" + (loc ? " findable around " + loc + " in " + monthName : "") + ", at most 7 evocative words, NEVER naming it. British spelling, no emojis.";
  const text = await callApi({ model: "claude-sonnet-4-6", max_tokens: 1000, messages: [{ role: "user", content: prompt }] });
  const clean = text.replace(/```json|```/g, "").trim();
  const s = clean.indexOf("{");
  const e = clean.lastIndexOf("}");
  const d = JSON.parse(s >= 0 && e > s ? clean.slice(s, e + 1) : clean);
  if (!d.quest) throw new Error("no quest");
  const nearby = (Array.isArray(d.nearby) ? d.nearby : []).slice(0, 3).map((t) => ({ name: String(t.name || "Wild thing"), rarity: TIERS[t.rarity] ? t.rarity : "common", category: CATS[t.category] ? t.category : "plants" }));
  const mystery = { hint: String((d.mystery && d.mystery.hint) || TEASER_FALLBACKS[0].hint) };
  return { quest: String(d.quest), nearby: nearby.length === 3 ? nearby : NEARBY_FALLBACKS, mystery };
}

async function evolveSpecies(common, sci, category) {
  const prompt =
    "In a nature-catching game, the player has now logged " + common + (sci ? " (" + sci + ")" : "") + " three times, and it evolves.\n" +
    'Respond ONLY minified JSON: {"title":"...","flavour":"...","abilities":["...","..."]}\n' +
    "Rules: title is a grander 3 to 6 word evolved name for this species, mythic but affectionate. flavour is at most 16 words, present tense, British spelling, no emojis. abilities are exactly two new invented ability names, 1 to 3 words, clearly upgraded and true to the species. NEVER state or imply edibility, medicinal use, or that anything is safe to touch, taste, handle or approach.";
  const text = await callApi({ model: "claude-sonnet-4-6", max_tokens: 1000, messages: [{ role: "user", content: prompt }] });
  const clean = text.replace(/```json|```/g, "").trim();
  const s = clean.indexOf("{");
  const e = clean.lastIndexOf("}");
  const d = JSON.parse(s >= 0 && e > s ? clean.slice(s, e + 1) : clean);
  d.abilities = Array.isArray(d.abilities) ? d.abilities.slice(0, 2).map(String) : [];
  return d;
}

